#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *S = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) {
            scanf("%d", &S[i]);
        }
        int count = 0;
        for (int i = 0; i < N; ++i) {
            int d;
            scanf("%d", &d);
            if (S[i] == d) ++count;
        }
        free(S);
        printf("%d
", count);
    }
    return 0;
}

